import json
import base64
import boto3
from botocore.exceptions import BotoCoreError, ClientError
import pickle as pkl

def lambda_handler(event, context):
    message = event['Records'][0]['Sns']['Message']
    
    # Base64 decoding and loading to Python dict
    json_str = base64.b64decode(message).decode('utf-8') 
    data = json.loads(json_str)
    
    try:
        user_actions = pkl.loads(data['userActions']) # use pickle to load nested objects
        
        # process deserialized data as per your requirements
        for action in user_actions: 
            print('Action Type: {}, User Id: {}'.format(action['type'], action['userId']))
    
    except Exception as e:
        print("Failed to deserialize and load complex object. Error: ", str(e))